import React from 'react'
import Helmet from 'react-helmet'

type Props = {
  title?: string
  description?: string
  lang?: string
  type?: string
  meta?: []
}

function SEO({ title = '', description = '', lang = 'en', type = 'website', meta = [] }: Props) {
  const metaDescription = description

  return (
    <Helmet
      htmlAttributes={{
        lang,
      }}
      title={title}
      meta={[
        {
          property: `og:title`,
          content: title,
        },
        {
          name: `twitter:title`,
          content: title,
        },
        {
          name: `description`,
          content: metaDescription,
        },
        {
          property: `og:description`,
          content: metaDescription,
        },
        {
          name: `twitter:description`,
          content: metaDescription,
        },
        {
          property: `og:type`,
          content: type,
        },
        {
          name: `twitter:card`,
          content: `summary`,
        },
        {
          property: `og:sitename`,
          content: title,
        },
      ].concat(meta)}
    />
  )
}

export { SEO }
